import{_ as t,o as d,c as e,a4 as o}from"./chunks/framework.BMymQDdR.js";const m=JSON.parse('{"title":"应用配置","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Application-Config.md","filePath":"zh/v3/designer/Application-Config.md","lastUpdated":1780630099000}'),a={name:"v3/designer/Application-Config.md"},r=o('<h1 id="应用配置" tabindex="-1">应用配置 <a class="header-anchor" href="#应用配置" aria-label="Permalink to &quot;应用配置&quot;">​</a></h1><p>应用配置用于设置应用程序的元数据信息，如标题、图标、版本号、权限等。通过 <strong>设置 &gt; 应用配置</strong>（快捷键 <code>Ctrl+F11</code> / macOS <code>Cmd+F11</code>）打开。</p><h2 id="通用配置" tabindex="-1">通用配置 <a class="header-anchor" href="#通用配置" aria-label="Permalink to &quot;通用配置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>输入类型</th><th>默认值/提示</th></tr></thead><tbody><tr><td>标题</td><td>应用程序的显示名称</td><td>文本输入</td><td>提示：<code>my energy app</code></td></tr><tr><td>标识</td><td>应用程序的唯一标识符（反向域名格式）</td><td>文本输入</td><td>提示：<code>company.product.app</code></td></tr><tr><td>描述</td><td>应用程序的描述信息</td><td>文本输入</td><td>提示：<code>your application description.</code></td></tr><tr><td>版本</td><td>应用程序版本号</td><td>文本输入</td><td>提示：<code>1.2.3.4</code></td></tr><tr><td>版权</td><td>应用程序的版权声明</td><td>文本输入</td><td>提示：<code>Copyright (C)</code></td></tr><tr><td>应用图标</td><td>应用程序的图标文件</td><td>图标选择器（点击上传）</td><td>支持 PNG 格式，最大 1024×1024</td></tr></tbody></table><h3 id="图标设置" tabindex="-1">图标设置 <a class="header-anchor" href="#图标设置" aria-label="Permalink to &quot;图标设置&quot;">​</a></h3><ul><li>支持上传 PNG 格式的图标文件</li><li>设计器自动将 PNG 转换为各平台所需格式： <ul><li><strong>Windows</strong> - 自动生成 <code>.ico</code> 格式</li><li><strong>macOS</strong> - 自动生成 <code>.icns</code> 格式</li><li><strong>Linux</strong> - 使用 <code>.png</code> 格式</li></ul></li><li>图标自动缩放到各平台要求的标准尺寸</li></ul><h2 id="windows-配置" tabindex="-1">Windows 配置 <a class="header-anchor" href="#windows-配置" aria-label="Permalink to &quot;Windows 配置&quot;">​</a></h2><h3 id="manifest-设置" tabindex="-1">Manifest 设置 <a class="header-anchor" href="#manifest-设置" aria-label="Permalink to &quot;Manifest 设置&quot;">​</a></h3><p>Windows Manifest 用于声明应用程序的兼容性、权限和系统行为。配置分为下拉选择项和复选框两类。</p><h4 id="下拉选择项" tabindex="-1">下拉选择项 <a class="header-anchor" href="#下拉选择项" aria-label="Permalink to &quot;下拉选择项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>可选值</th><th>默认值</th></tr></thead><tbody><tr><td>兼容性操作系统</td><td>目标 Windows 最低版本</td><td><code>Windows Vista</code>、<code>Windows 7</code>、<code>Windows 8</code>、<code>Windows 8.1</code>、<code>Windows 10</code>、<code>Windows 11</code></td><td><code>Windows Vista</code></td></tr><tr><td>DPI 感知</td><td>高 DPI 显示支持模式</td><td><code>System (开启)</code> - 系统级 DPI 感知<br><code>UnAware (关闭)</code> - 不感知 DPI<br><code>PerMonitor (true/PM)</code> - 每显示器感知<br><code>PerMonitorV2 (true/PM-V2)</code> - 每显示器感知 V2</td><td><code>System (开启)</code></td></tr><tr><td>运行级别</td><td>应用程序权限运行级别</td><td><code>AsInvoker (当前用户)</code> - 以当前用户权限运行<br><code>HighestAvailable (最高可用权限)</code> - 以最高可用权限运行<br><code>RequireAdministrator (要求管理员)</code> - 要求管理员权限</td><td><code>AsInvoker (当前用户)</code></td></tr></tbody></table><h4 id="复选框选项" tabindex="-1">复选框选项 <a class="header-anchor" href="#复选框选项" aria-label="Permalink to &quot;复选框选项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>默认值</th></tr></thead><tbody><tr><td>uiAccess (用户界面访问)</td><td>允许应用程序访问受保护的用户界面元素</td><td>关闭</td></tr><tr><td>autoElevate (自动提权)</td><td>自动请求提升权限（需配合管理员运行级别）</td><td>关闭</td></tr><tr><td>DisableTheming (禁用主题)</td><td>禁用 Windows 视觉主题渲染</td><td>关闭</td></tr><tr><td>disableWindowFiltering (禁用窗口过滤)</td><td>禁用窗口过滤机制</td><td>关闭</td></tr><tr><td>highResolutionScrollingAware (高分辨率滚动)</td><td>启用高分辨率显示器的平滑滚动支持</td><td>开启</td></tr><tr><td>ultraHighResolutionScrollingAware (超高分辨率滚动)</td><td>启用超高分辨率显示器的滚动支持</td><td>开启</td></tr><tr><td>longPathAware (启用长路径支持)</td><td>支持超过 260 字符的文件路径</td><td>开启</td></tr><tr><td>printerDriverIsolation (打印驱动隔离)</td><td>将打印机驱动程序隔离在独立进程中运行</td><td>关闭</td></tr><tr><td>gdiScaling (GDI 自动缩放)</td><td>启用 GDI 自动缩放以改善高 DPI 显示效果</td><td>开启</td></tr><tr><td>segmentHeap (分段堆)</td><td>使用段堆内存管理方式，可降低内存占用</td><td>关闭</td></tr><tr><td>useCommonControlsV6 (视觉样式)</td><td>使用 Common Controls v6，启用现代视觉样式</td><td>开启</td></tr></tbody></table><h2 id="macos-配置" tabindex="-1">macOS 配置 <a class="header-anchor" href="#macos-配置" aria-label="Permalink to &quot;macOS 配置&quot;">​</a></h2><h3 id="info-plist-设置" tabindex="-1">Info.plist 设置 <a class="header-anchor" href="#info-plist-设置" aria-label="Permalink to &quot;Info.plist 设置&quot;">​</a></h3><p>Info.plist 是 macOS 应用包的核心配置文件，定义了应用的元数据和系统行为。</p><h4 id="下拉选择项-1" tabindex="-1">下拉选择项 <a class="header-anchor" href="#下拉选择项-1" aria-label="Permalink to &quot;下拉选择项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>可选值</th><th>默认值</th></tr></thead><tbody><tr><td>LSUIElement (运行模式)</td><td>控制应用是否在 Dock 中显示图标</td><td><code>false (常规前台应用)</code> - 正常显示在 Dock<br><code>true (后台应用, 无 Dock 图标)</code> - 后台运行，不显示 Dock 图标</td><td><code>false (常规前台应用)</code></td></tr><tr><td>LS Minimum System Version (最低系统版本)</td><td>应用支持的最低 macOS 版本</td><td><code>10.15 (Intel)</code> - 支持 Intel Mac<br><code>11.0 (Apple Silicon)</code> - 支持 Apple Silicon 芯片</td><td><code>10.15 (Intel)</code></td></tr></tbody></table><h4 id="文本输入项" tabindex="-1">文本输入项 <a class="header-anchor" href="#文本输入项" aria-label="Permalink to &quot;文本输入项&quot;">​</a></h4><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th><th>提示信息</th></tr></thead><tbody><tr><td>CFBundleName (短标题)</td><td>应用的短显示名称</td><td><code>应用的短显示名称, 默认: 构建二进制文件名</code></td></tr><tr><td>CFBundleLocalizations (本地化语言列表)</td><td>支持的语言本地化列表，逗号分隔</td><td><code>本地化语言列表, 豆号分隔 zh_CN,en</code></td></tr></tbody></table><h4 id="自动生成的-info-plist-字段" tabindex="-1">自动生成的 Info.plist 字段 <a class="header-anchor" href="#自动生成的-info-plist-字段" aria-label="Permalink to &quot;自动生成的 Info.plist 字段&quot;">​</a></h4><p>以下字段在打包时由设计器根据通用配置自动生成，无需手动设置：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>数据来源</th></tr></thead><tbody><tr><td>CFBundleExecutable</td><td>可执行文件名</td><td>项目构建文件名</td></tr><tr><td>CFBundleDisplayName</td><td>应用显示名称</td><td>通用配置中的&quot;标题&quot;</td></tr><tr><td>CFBundleIdentifier</td><td>应用唯一标识符</td><td>通用配置中的&quot;标识&quot;</td></tr><tr><td>CFBundleVersion</td><td>内部版本号</td><td>通用配置中的&quot;版本&quot;</td></tr><tr><td>CFBundleShortVersionString</td><td>短版本号</td><td>通用配置中的&quot;版本&quot;</td></tr><tr><td>CFBundleGetInfoString</td><td>简介信息</td><td>通用配置中的&quot;描述&quot;</td></tr><tr><td>CFBundleIconFile</td><td>图标文件名</td><td>自动生成的 <code>.icns</code> 文件名</td></tr><tr><td>NSHumanReadableCopyright</td><td>版权信息</td><td>通用配置中的&quot;版权&quot;</td></tr></tbody></table><h2 id="linux-配置" tabindex="-1">Linux 配置 <a class="header-anchor" href="#linux-配置" aria-label="Permalink to &quot;Linux 配置&quot;">​</a></h2><p>Linux 平台目前无特定的应用配置选项（相关配置在打包配置中设置）。</p><h2 id="保存配置" tabindex="-1">保存配置 <a class="header-anchor" href="#保存配置" aria-label="Permalink to &quot;保存配置&quot;">​</a></h2><p>修改配置后点击&quot;保存&quot;按钮，配置信息写入项目的 <code>.egp</code> 配置文件。同时自动更新应用图标文件到项目的资源目录。</p>',27),i=[r];function n(c,l,h,s,u,b){return d(),e("div",null,i)}const f=t(a,[["render",n]]);export{m as __pageData,f as default};
